#[test]
fn disco_ping() {
    let bin = include_bytes!("../fixtures/disco_ping.bin");
    let msg = rustscale_disco::Message::parse(bin).expect("parse disco_ping");
    let re_encoded = msg.marshal();
    assert_binary_roundtrip(bin, &re_encoded);
}

